// Base class for internal microservice workers
class MicroserviceBase {
  constructor(serviceName) {
    this.serviceName = serviceName;
    this.routes = new Map();
  }

  registerRoute(method, pattern, handler) {
    const key = `${method}:${pattern}`;
    this.routes.set(key, { method, pattern, handler });
  }

  async handleRequest(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    // Handle health check
    if (path === '/health') {
      return this.healthResponse();
    }

    // Handle OPTIONS for CORS preflight
    if (method === 'OPTIONS') {
      return new Response(null, { status: 204 });
    }

    // Match routes
    for (const [, route] of this.routes) {
      if (route.method !== method && route.method !== '*') continue;

      const params = this.matchPattern(route.pattern, path);
      if (params !== null) {
        try {
          const context = {
            params,
            query: Object.fromEntries(url.searchParams),
            env,
            ctx,
            requestId: request.headers.get('X-Gateway-Request-Id') || 'direct',
          };
          return await route.handler(request, context);
        } catch (err) {
          console.error(`[${this.serviceName}] Handler error: ${err.message}`);
          return this.errorResponse(500, 'Internal Service Error', err.message);
        }
      }
    }

    return this.errorResponse(404, 'Route Not Found', `${method} ${path} not found in ${this.serviceName}`);
  }

  matchPattern(pattern, path) {
    const patternParts = pattern.split('/').filter(Boolean);
    const pathParts = path.split('/').filter(Boolean);

    if (patternParts.length !== pathParts.length) return null;

    const params = {};
    for (let i = 0; i < patternParts.length; i++) {
      if (patternParts[i].startsWith(':')) {
        params[patternParts[i].slice(1)] = pathParts[i];
      } else if (patternParts[i] !== pathParts[i]) {
        return null;
      }
    }
    return params;
  }

  jsonResponse(data, status = 200) {
    return new Response(JSON.stringify({
      service: this.serviceName,
      data,
      timestamp: new Date().toISOString()
    }), {
      status,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  errorResponse(status, error, message) {
    return new Response(JSON.stringify({
      service: this.serviceName,
      error,
      message,
      timestamp: new Date().toISOString()
    }), {
      status,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  healthResponse() {
    return new Response(JSON.stringify({
      service: this.serviceName,
      status: 'healthy',
      timestamp: new Date().toISOString()
    }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' }
    });
  }
}

// User Service Implementation
const userService = new MicroserviceBase('user-service');

// In-memory store for demo (use KV/D1/Durable Objects in production)
const usersStore = new Map([
  ['1', { id: '1', name: 'Alice Johnson', email: 'alice@example.com', role: 'admin' }],
  ['2', { id: '2', name: 'Bob Smith', email: 'bob@example.com', role: 'user' }],
]);

// GET /users - List all users
userService.registerRoute('GET', '/users', async (request, context) => {
  const users = Array.from(usersStore.values());

  // Support filtering by role
  if (context.query.role) {
    const filtered = users.filter(u => u.role === context.query.role);
    return userService.jsonResponse(filtered);
  }

  return userService.jsonResponse(users);
});

// GET /users/:id - Get user by ID
userService.registerRoute('GET', '/users/:id', async (request, context) => {
  const user = usersStore.get(context.params.id);
  if (!user) {
    return userService.errorResponse(404, 'User Not Found', `No user with id ${context.params.id}`);
  }
  return userService.jsonResponse(user);
});

// POST /users - Create a new user
userService.registerRoute('POST', '/users', async (request, context) => {
  const body = await request.json();

  if (!body.name || !body.email) {
    return userService.errorResponse(400, 'Validation Error', 'name and email are required');
  }

  const id = crypto.randomUUID().split('-')[0];
  const newUser = {
    id,
    name: body.name,
    email: body.email,
    role: body.role || 'user',
    createdAt: new Date().toISOString()
  };

  usersStore.set(id, newUser);

  // If we need to notify other services, we can use service bindings here too
  // e.g., await context.env.NOTIFICATION_SERVICE.fetch(...)

  return userService.jsonResponse(newUser, 201);
});

// PUT /users/:id - Update user
userService.registerRoute('PUT', '/users/:id', async (request, context) => {
  const existing = usersStore.get(context.params.id);
  if (!existing) {
    return userService.errorResponse(404, 'User Not Found', `No user with id ${context.params.id}`);
  }

  const body = await request.json();
  const updated = {
    ...existing,
    ...body,
    id: existing.id, // prevent ID override
    updatedAt: new Date().toISOString()
  };

  usersStore.set(context.params.id, updated);
  return userService.jsonResponse(updated);
});

// DELETE /users/:id - Delete user
userService.registerRoute('DELETE', '/users/:id', async (request, context) => {
  if (!usersStore.has(context.params.id)) {
    return userService.errorResponse(404, 'User Not Found', `No user with id ${context.params.id}`);
  }

  usersStore.delete(context.params.id);
  return userService.jsonResponse({ deleted: true, id: context.params.id });
});

// Internal endpoint: validate user (called by other services via service binding)
userService.registerRoute('GET', '/internal/validate/:id', async (request, context) => {
  const user = usersStore.get(context.params.id);
  return userService.jsonResponse({
    valid: !!user,
    userId: context.params.id,
    role: user?.role || null
  });
});

export default {
  async fetch(request, env, ctx) {
    return userService.handleRequest(request, env, ctx);
  }
};


